# Lidando com rate limit
import time

def call_with_retry(api_func, max_retries=3):
    for i in range(max_retries):
        try:
            return api_func()
        except RateLimitError:
            wait = 2 ** i  # exponential backoff
            time.sleep(wait)
    raise Exception('Max retries')
